from flask import Flask, request, jsonify, redirect
import secrets
import string
from datetime import datetime

app = Flask(__name__)

# In-memory storage for authorization codes
auth_codes = {}
tokens = {}

# Client credentials storage
clients = {
    "client1": {"client_secret": "secret1", "redirect_uris": ["http://localhost:5000/callback"]}
}

# User storage (mock)
