def generate_code(length=32):
    """Generate a secure random authorization code"""
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(length))

def generate_token(length=64):
    """Generate a secure random access token"""
    return ''.join(secrets.choice(string.ascii_letters + string.digits) for _ in range(length))

@app.route('/authorize', methods=['GET'])
def authorize():
    """Authorization endpoint"""
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    
    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if client_id not in clients:
        return jsonify({"error": "Invalid client"}), 400
    
    if redirect_uri not in clients[client_id]["redirect_uris"]:
        return jsonify({"error": "Invalid redirect URI"}), 400
    
    if response_type != "code":
        return jsonify({"error": "Invalid response type"}), 400
    
    # Generate authorization code
    code = generate_code()
    auth_codes[code] = "user1"  # Mock user
    
    # Redirect with authorization code
    return redirect(f"{redirect_uri}?code={code}")

@app.route('/token', methods=['POST'])
def token():
    """Token exchange endpoint"""
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    grant_type = request.form.get('grant_type')
    
    if not all([client_id, client_secret, code, grant_type]):
        return jsonify({"error": "Missing required parameters"}), 400
    
    if grant_type != "authorization_code":
        return jsonify({"error": "Invalid grant type"}), 400
    
    # Validate client credentials
    if client_id not in clients or clients[client_id]["client_secret"] != client_secret:
        return jsonify({"error": "Invalid client credentials"}), 400
    
    # Validate authorization code
    if code not in auth_codes:
        return jsonify({"error": "Invalid authorization code"}), 400
    
    # Generate access token
    token = generate_token()
    user_id = auth_codes[code]
    
    # Store token
    tokens[token] = {
        "user_id": user_id,
        "expires_at": datetime.now().timestamp() + 3600  # 1 hour expiry
    }
    
    # Remove used authorization code
    del auth_codes[code]
    
    return jsonify({
        "access_token": token,
        "token_type": "Bearer",
        "expires_in": 3600
    })

# Additional endpoint for token validation
@app.route('/validate', methods=['POST'])
def validate_token():
    """Validate access token"""
    token = request.form.get('access_token')
    
    if not token:
        return jsonify({"error": "Missing access token"}), 400
    
    if token not in tokens:
        return jsonify({"error": "Invalid token"}), 401
    
    return jsonify({"valid": True, "user_id": tokens[token]["user_id"]})

